+
+apply plugin: 'jacoco'
+
+jacoco {
+    toolVersion = '0.8.14' // Officially supports Java 25 (class file major version 69)
+}
+
+jacocoTestCoverageVerification {
+    doLast {
+        println 'Jacoco coverage checks complete!'
+    }
+
+    afterEvaluate {
+        getClassDirectories().setFrom(classDirectories.files.collect {
+            fileTree(it) {
+                // Exclude classes from coverage verification that are fully or partially skipped when testing
+                // the OS provided Oracle Linux 9+ FIPS module or due to an absence of FIPS 186-4 type domain
+                // parameters. OL9+ FIPS module does not support DESEDE or DSA keys.
+                // It also does not support FIPS 186-4 type domain parameters, which impacts DH key testing.
+                exclude(
+                        'com/oracle/jipher/internal/key/JceDhPublicKey.class',
+                        'com/oracle/jipher/internal/key/JceDhPrivateKey.class',
+                        'com/oracle/jipher/internal/key/JceDsaPublicKey.class',
+                        'com/oracle/jipher/internal/spi/*DesEde*.class',
+                        'com/oracle/jipher/internal/spi/*DESede*.class',
+                        'com/oracle/jipher/internal/spi/DhKeyFactory.class',
+                        'com/oracle/jipher/internal/spi/DsaKeyFactory.class',
+                        'com/oracle/jipher/internal/openssl/Pkey.class'
+                )
+            }
+        })
+    }
+
+    mustRunAfter jacocoTestReport
+    violationRules {
+        rule {
+            element = 'PACKAGE'
+            includes = ['com.oracle.*']
+            excludes = [
+                    // Platform dependent code has distinct code coverage targets (defined below)
+                    'com.oracle.jipher.internal.platform'
+            ]
+            limit {
+                counter = 'BRANCH'
+                minimum = 0.80
+            }
+        }
+        rule {
+            element = 'PACKAGE'
+            includes = ['com.oracle.*']
+            excludes = [
+                    // Platform dependent code has distinct code coverage targets (defined below)
+                    'com.oracle.jipher.internal.platform'
+            ]
+            limit {
+                counter = 'LINE'
+                minimum = 0.80
+            }
+        }
+
+        // As the source code in the 'com.oracle.jipher.internal.platform' package is platform dependent
+        // only a fraction of the code gets run on a single platform for a given set of system property settings.
+        rule {
+            element = 'PACKAGE'
+            includes = ['com.oracle.jipher.internal.platform*']
+            limit {
+                counter = 'BRANCH'
+                minimum = 0.20
+            }
+        }
+        rule {
+            element = 'PACKAGE'
+            includes = ['com.oracle.jipher.internal.platform*']
+            limit {
+                counter = 'LINE'
+                minimum = 0.25
+            }
+        }
+    }
+}
+jacocoTestReport {
+    reports {
+        xml.required = false
+        csv.required = false
+    }
+    afterEvaluate {
+        classDirectories.setFrom(classDirectories.files.collect {
+            fileTree(dir: it, excludes: [
+                '**/com/oracle/jipher/internal/openssl/ffm/EvpRandCtx.class' // Defer requiring good testing coverage of EvpRandCtx since EvpRandCtx is not yet used by Jipher
+            ])
+        })
+    }
+    doFirst {
+        println 'Creating Jacoco Coverage Report'
+    }
+}
+
+gradle.taskGraph.whenReady { taskGraph ->
+    if (project.ext.properties.disableSignJar == 'true') {
+        signJar.enabled = false
+    }
+    jacocoTestReport {
+        executionData project.tasks['test'], project.tasks['lifeCycleHookTest'], project.tasks['integrationTest']
+    }
+    jacocoTestCoverageVerification {
+        executionData project.tasks['test'], project.tasks['lifeCycleHookTest'], project.tasks['integrationTest']
+    }
+}

