+            }
+        };
+    }
+
+    public static RSAPublicKey getDummyRsaPublicKey(final byte[] enc) {
+        return new RSAPublicKey() {
+            @Override
+            public BigInteger getPublicExponent() {
+                return null;
+            }
+
