+        } catch (InvalidKeyException e) {
+            if (expectInvalidKeyException) return;
+            throw (e);
+        }
+        assertFalse(expectInvalidKeyException);
+
+        byte[] result = ka.generateSecret();
+        assertArrayEquals(tv.getSecret(), result);
+    }
