+    private static boolean usesFIPS140_4TypeDomainParameters(KeyPairTestData kp) {
+        if (kp == null) {
+            return false;
+        }
+        if (kp.getAlg().equals("DH")) {
+            return !(kp.getSecParam().startsWith("MODP-") || kp.getSecParam().startsWith("ffdhe"));
