+
+
+@RunWith(Parameterized.class)
+public class KeyFactoryAlgStringTest {
+
+    @Parameterized.Parameters(name="{0}")
+    public static Collection<Object[]> aliases() {
+        return Arrays.asList(
+                new Object[]{
+                        "DH", new String[] {"OID.1.2.840.113549.1.3.1", "1.2.840.113549.1.3.1"}
+                },
+                new Object[]{
+                        "DSA", new String[] {"OID.1.2.840.10040.4.1", "1.2.840.10040.4.1",
+                        "OID.1.3.14.3.2.12", "1.3.14.3.2.12"}
+                },
+                new Object[]{
+                        "EC", new String[] {"EllipticCurve",
+                        "OID.1.2.840.10045.2.1", "1.2.840.10045.2.1"}
+                },
+                new Object[]{
+                        "RSA", new String[]{"OID.1.2.840.113549.1.1", "1.2.840.113549.1.1",
+                        "OID.1.2.840.113549.1.1.1", "1.2.840.113549.1.1.1"}
+                },
+                new Object[]{
+                        "RSASSA-PSS", new String[] {"PSS",
+                        "OID.1.2.840.113549.1.1.10", "1.2.840.113549.1.1.10"}
+                }
+        );
+    }
+
+    private final String alg;
+    private final String[] aliases;
+
+    public KeyFactoryAlgStringTest(String alg, String[] aliases) {
+        Assume.assumeTrue(FipsProviderInfoUtil.isDSASupported() || !alg.equals("DSA"));
+        this.alg = alg;
+        this.aliases = aliases;
+    }
+
+    @Test
+    public void testAlgorithm() throws Exception {
+        Provider provider  = ProviderUtil.get();
+        Provider.Service service = provider.getService("KeyFactory", alg);
+        Assert.assertNotNull("Provider does not contain KeyFactory." + alg, service);
+    }
+
+    @Test
+    public void testAliases() throws Exception {
+        Provider provider  = ProviderUtil.get();
+        Provider.Service service = provider.getService("KeyFactory", alg);
