+package com.oracle.test.integration.keyfactory;
+
+import java.util.Collection;
+import javax.crypto.SecretKeyFactory;
+import javax.crypto.interfaces.PBEKey;
+import javax.crypto.spec.PBEKeySpec;
+
+import org.junit.Assume;
+import org.junit.Test;
+import org.junit.runner.RunWith;
+import org.junit.runners.Parameterized;
+import org.junit.runners.Parameterized.Parameters;
+
+import com.oracle.jiphertest.testdata.PbkdfTestVector;
+import com.oracle.jiphertest.testdata.TestData;
+import com.oracle.jiphertest.util.EnvUtil;
+import com.oracle.jiphertest.util.FipsProviderInfoUtil;
+import com.oracle.jiphertest.util.ProviderUtil;
+
+import static org.junit.Assert.assertArrayEquals;
+import static org.junit.Assert.assertEquals;
+
+
+/**
+ * Test Kdf SecretKeyFactory implementations in the provider
+ * using test vectors.
+ */
+@RunWith(Parameterized.class)
+public class PbkdfKeyFactoryVectorTest {
+
+    @Parameters(name="{0}:{index}")
+    public static Collection<Object[]> data() throws Exception {
+        return TestData.forParameterized(PbkdfTestVector.class);
+    }
+
+    private final PbkdfTestVector tv;
+
+    public PbkdfKeyFactoryVectorTest(String description, PbkdfTestVector tv) {
+        Assume.assumeTrue(FipsProviderInfoUtil.getKDFMinPwdLen() <= tv.getPasswordChars().length);
+        Assume.assumeTrue(EnvUtil.getMinPbkdf2PasswordLength() <= tv.getPasswordChars().length);
+        this.tv = tv;
+    }
+
+    @Test
+    public void test() throws Exception {
+        SecretKeyFactory skf = ProviderUtil.getSecretKeyFactory(tv.getAlg());
+        char[] password = tv.getPasswordChars();
+        byte[] salt = tv.getSalt();
+        int iter = tv.getIterationCount();
+        byte[] dk = tv.getDk();
+        PBEKeySpec ks = new PBEKeySpec(password, salt, iter, dk.length * 8);
+        PBEKey key = (PBEKey) skf.generateSecret(ks);
+        assertArrayEquals(dk, key.getEncoded());
+        assertArrayEquals(password, key.getPassword());
+        assertArrayEquals(salt, key.getSalt());
+        assertEquals(iter, key.getIterationCount());
+        assertEquals(tv.getAlg(), key.getAlgorithm());
+        assertEquals("RAW", key.getFormat());
+    }
+
+}

