+        mac = ProviderUtil.getMac("HmacSHA256");
+        secretKey = new SecretKeySpec(TEST_KEY, "HmacSHA256");
+        altSecretKey = new SecretKeySpec(ALT_TEST_KEY, "HmacSHA256");
