+
+    private static final byte[] SAMPLE_IV = TestUtil.hexStringToByteArray("00112233445566778899aabbccddeeff");
+
+    private static byte[] ivBytes(int len) {
+        return Arrays.copyOf(SAMPLE_IV, len);
