+package com.oracle.jiphertest.model;
+
+import javax.crypto.BadPaddingException;
+import javax.crypto.IllegalBlockSizeException;
+
+abstract public class AbstractCipherModel implements CipherModel {
+    protected int bufferedSize = 0;
+    protected boolean decrypt;
+
+    public AbstractCipherModel() {
+        this.bufferedSize = 0;
+    }
+
+    abstract int getOutputSize(int inputSize, boolean doFinal);
+
+    public void init(boolean decrypt) {
+        this.bufferedSize = 0;
+        this.decrypt = decrypt;
+    }
+
+    public int getOutputSize(int inputSize) {
+        return Math.max(getOutputSize(inputSize, false), getOutputSize(inputSize, true));
+    }
+
+    public int update(int inputSize) {
+        int outputSize = getOutputSize(inputSize, false);
+        this.bufferedSize += inputSize - outputSize;
+
+        return outputSize;
+    }
+
+    public int doFinal(int inputSize) throws IllegalBlockSizeException, BadPaddingException {
+        int outputSize = getOutputSize(inputSize, true);
+        this.bufferedSize = 0;
+
+        return outputSize;
+    }
+}

