+package com.oracle.jiphertest.model;
+
+public class AuthenticatedStreamCipherModel extends StreamCipherModel {
+    static boolean CIPHER_AEAD_STREAM_VALUE = Boolean.getBoolean("jipher.cipher.AEAD.stream");
+
+    protected int tagSize;
+    public AuthenticatedStreamCipherModel(int tagSize) {
+        super();
+        this.tagSize = tagSize;
+    }
+
+    @Override
+    protected int getOutputSize(int inputSize, boolean doFinal) {
+        int dataSize = this.bufferedSize + inputSize;
+
+        if (doFinal) {
+            if (this.decrypt) {
+                return Math.max(0, dataSize - this.tagSize);
+            } else {
+                return dataSize + this.tagSize;
+            }
+        } else {
+            if (this.decrypt) {
+                if (CIPHER_AEAD_STREAM_VALUE) {
+                    // Retain (up to) the last tagSize bytes of the input
+                    // in case they represent the tag appended to the end of the ciphertext
+                    return Math.max(0, dataSize - this.tagSize);
+                } else {
+                    // Decrypted text is only returned after it has been authenticated
+                    // by validating the authentication tag in doFinal()
+                    return 0;
+                }
+            } else {
+                return dataSize;
+            }
+        }
+    }
+}

