+package com.oracle.jiphertest.testdata;
+
+import java.util.ArrayList;
+import java.util.List;
+import java.util.Random;
+
+public class KeyPairs {
+
+    private final List<KeyPairTestData> keyPairs;
+
+    public KeyPairs(List<KeyPairTestData> keys) {
+        this.keyPairs = keys;
+    }
+
+    private List<KeyPairTestData> getAll(String alg, String secParams, String prov) {
+        List<KeyPairTestData> kps = new ArrayList<>();
+        TestDataMatcher matcher = DataMatchers.alg(alg).secParam(secParams).prov(prov);
+        for (KeyPairTestData kp : this.keyPairs) {
+            if (matcher.matches(kp)) {
+                kps.add(kp);
+            }
+        }
+        return kps;
+    }
+    public KeyPairTestData getAny(String alg, String secParams, String prov) {
+        List<KeyPairTestData> kps = getAll(alg, secParams, prov);
+        if (kps.isEmpty()) {
+            throw new Error("No key pairs matched search data");
+        }
+        return kps.get(new Random().nextInt(kps.size()));
+    }
+
+    public KeyPairTestData getAny(String alg, String secParams) {
+        return getAny(alg, secParams, null);
+    }
+}

