+package com.oracle.jiphertest.testdata;
+
+import java.util.ArrayList;
+import java.util.List;
+import java.util.Random;
+
+public class Params {
+
+    List<ParameterTestData> paramList;
+
+    public Params(List<ParameterTestData> params) {
+        this.paramList = params;
+    }
+
+    private List<ParameterTestData> getAll(String alg, String secParams, String prov) {
+        List<ParameterTestData> kps = new ArrayList<>();
+        TestDataMatcher matcher = DataMatchers.alg(alg).secParam(secParams).prov(prov);
+        for (ParameterTestData kp : this.paramList) {
+            if (matcher.matches(kp)) {
+                kps.add(kp);
+            }
+        }
+        return kps;
+    }
+
+    public ParameterTestData getAny(String alg, String secParams, String prov) {
+        List<ParameterTestData> params = getAll(alg, secParams, prov);
+        if (params.isEmpty()) {
+            throw new Error("No params matched search data");
+        }
+        return params.get(new Random().nextInt(params.size()));
+    }
+}

