+public class AlgorithmUtil {
+
+    public enum Algorithm {
+        SHA1("SHA-1", "1.3.14.3.2.26", "SHA", "SHA1"),
+        SHA224("SHA-224", "2.16.840.1.101.3.4.2.4", "SHA224"),
+        SHA256("SHA-256", "2.16.840.1.101.3.4.2.1", "SHA256"),
+        SHA384("SHA-384", "2.16.840.1.101.3.4.2.2", "SHA384"),
+        SHA512("SHA-512", "2.16.840.1.101.3.4.2.3", "SHA512"),
+        SHA_512$224("SHA-512/224","2.16.840.1.101.3.4.2.5",  "SHA512/224"),
+        SHA_512$256("SHA-512/256","2.16.840.1.101.3.4.2.6", "SHA512/256"),
+        SHA3_224("SHA3-224", "2.16.840.1.101.3.4.2.7"),
+        SHA3_256("SHA3-256", "2.16.840.1.101.3.4.2.8"),
+        SHA3_384("SHA3-384", "2.16.840.1.101.3.4.2.9"),
+        SHA3_512("SHA3-512", "2.16.840.1.101.3.4.2.10");
+
+        private final String standardName;
+        private final String oid;
+        private final String[] aliases;
+
+        Algorithm(String standardName, String oid, String... aliases) {
+            this.standardName = standardName;
+            this.oid = oid;
+            this.aliases = aliases;
+        }
+
+        public String getStandardName() {
+            return this.standardName;
+        }
+
+        public String getOID() {
+            return this.oid;
+        }
+
+        public static Algorithm byName(String name) {
+            for (Algorithm algorithm : Algorithm.values()) {
+                if (algorithm.standardName.equalsIgnoreCase(name)) {
+                    return algorithm;
+                }
+                if (algorithm.oid.equalsIgnoreCase(name) || ("OID." + algorithm.oid).equalsIgnoreCase(name)) {
+                    return algorithm;
+                }
+                if (algorithm.aliases != null) {
+                    for (String alias : algorithm.aliases) {
+                        if (alias.equalsIgnoreCase(name)) {
+                            return algorithm;
+                        }
+                    }
+                }
+            }
+            return null;
+        }
+    }
+
+    public static String digestFromDigestSignature(String digestSignatureName) {
+        String digestName = digestSignatureName.substring(0, digestSignatureName.indexOf("with"));
