+            DSA_IS_SUPPORTED = true;
+            SHA1_DIGEST_SIGNATURES_ARE_SUPPORTED = true;
+            FIPS_186_4_TYPE_DOMAIN_PARAMETERS_SUPPORTED = true;
+            KDF_MIN_PWD_LEN = 0;
+        }
