+        System.arraycopy(x, xOffset, encodedPoint, encodedPoint.length - fLen - xLen, xLen);
+        System.arraycopy(y, yOffset, encodedPoint, encodedPoint.length - yLen, yLen);
+        return encodedPoint;
+    }
