+    int ERR_RFLAG_COMMON      = 0x2 << ERR_RFLAGS_OFFSET;
+    int ERR_R_FATAL           = ERR_RFLAG_FATAL | ERR_RFLAG_COMMON;
+
+    int ERR_R_MALLOC_FAILURE  = 256 | ERR_R_FATAL;
+
+    int ERR_LIB_NONE          = 1;
+    int ERR_LIB_SYS           = 2;
+    int ERR_LIB_BN            = 3;
+    int ERR_LIB_RSA           = 4;
+    int ERR_LIB_DH            = 5;
+    int ERR_LIB_EVP           = 6;
+    int ERR_LIB_BUF           = 7;
+    int ERR_LIB_OBJ           = 8;
+    int ERR_LIB_PEM           = 9;
+    int ERR_LIB_DSA           = 10;
+    int ERR_LIB_X509          = 11;
+    int ERR_LIB_ASN1          = 13;
+    int ERR_LIB_CONF          = 14;
+    int ERR_LIB_CRYPTO        = 15;
+    int ERR_LIB_EC            = 16;
+    int ERR_LIB_SSL           = 20;
+    int ERR_LIB_BIO           = 32;
+    int ERR_LIB_PKCS7         = 33;
+    int ERR_LIB_X509V3        = 34;
+    int ERR_LIB_PKCS12        = 35;
+    int ERR_LIB_RAND          = 36;
+    int ERR_LIB_DSO           = 37;
+    int ERR_LIB_ENGINE        = 38;
+    int ERR_LIB_OCSP          = 39;
+    int ERR_LIB_UI            = 40;
+    int ERR_LIB_COMP          = 41;
+    int ERR_LIB_ECDSA         = 42;
+    int ERR_LIB_ECDH          = 43;
+    int ERR_LIB_OSSL_STORE    = 44;
+    int ERR_LIB_FIPS          = 45;
+
+    int EVP_R_NO_CIPHER_SET   = 131;
+    int EVP_R_NO_DIGEST_SET   = 139;
+    int EVP_R_MESSAGE_DIGEST_IS_NULL = 159;
+    int EVP_R_PROVIDER_SIGNATURE_FAILURE = 234;
