+package com.oracle.jipher.internal.openssl;
+
+import java.text.ParseException;
+import java.util.List;
+
+import com.oracle.jipher.internal.common.ToolkitProperties;
+
+public abstract class VersionSanctioner {
+
+    protected static boolean accept(String versionString, String versionRangesString) throws IllegalArgumentException, ParseException {
+        List<VersionRange> versionRanges = VersionRange.parse(versionRangesString);
+
+        // If all versions are sanctioned then act as though version sanctioning is disabled.
+        // That is, do not process versionString which may be null or otherwise unparsable.
+        if (versionRanges.stream().anyMatch(
+                versionRange -> versionRange.getFrom() == null && versionRange.getTo() == null)) {
+            return true;
+        }
+
+        Version version = Version.of(versionString);
+        return versionRanges.stream().anyMatch(versionRange -> versionRange.contains(version));
+    }
+
+
+    public static final class CryptoLibrary extends VersionSanctioner {
+        private static final String VERSION_RANGES_STRING =
+                ToolkitProperties.getOpenSSLUseOsInstanceValue() ?
+                        ToolkitProperties.getOpensslSanctionedOsProvidedCryptoLibraryVersionsValue() :
+                        ToolkitProperties.getOpensslSanctionedCryptoLibraryVersionsValue();
+
+        public static boolean accept(String versionString) throws IllegalArgumentException, ParseException {
+            return accept(versionString, VERSION_RANGES_STRING);
+        }
+
+        public static String getSanctionedVersions() {
+            return VERSION_RANGES_STRING;
+        }
+    }
+
+    public static final class FipsProvider extends VersionSanctioner {
+        private static final String VERSION_RANGES_STRING =
+                ToolkitProperties.getOpenSSLUseOsInstanceValue() ?
+                        ToolkitProperties.getOpensslSanctionedOsProvidedFipsProviderVersionsValue() :
+                        ToolkitProperties.getOpensslSanctionedFipsProviderVersionsValue();
+
+        public static boolean accept(String versionString) throws IllegalArgumentException, ParseException {
+            return accept(versionString, VERSION_RANGES_STRING);
+        }
+
+        public static String getSanctionedVersions() {
+            return VERSION_RANGES_STRING;
+        }
+    }
+}

