+    static MemorySegment lifecycleHook(OpType opType, String funcName, MemorySegment ptr) {
+        NativeObjectLifecycleCallback cb = lifecycleCallback;
+        if (cb != null && ptr != null) {
+            long address = ptr.address();
+            if (address != 0L) {
+                try {
+                    cb.lifecycleOp(opType, funcName, address);
+                } catch (Throwable t) {
+                    t.printStackTrace();
+                }
+            }
+        }
+        return ptr;
+    }
