+        public boolean supportsMode(CipherMode m) {
+            return this.mode == m;
+        }
+
+        @Override
+        public boolean supportsPadding(CipherMode m, CipherPadding padding) {
+            return this.mode == m && this.pad == padding;
+        }
+    }
