+    CipherParameters(CipherAlg alg) {
+        this.alg = alg;
+    }
+
+    @Override
+    protected byte[] engineGetEncoded() {
+        return Asn1.newOctetString(this.ivSpec.getIV()).encodeDerOctets();
+    }
