+    private static final Asn1BerValue ID_DH_KEY_AGREEMENT = newOid("1.2.840.113549.1.3.1");
+    private static final Asn1BerValue ID_DH_PUBLIC_NUMBER = newOid("1.2.840.10046.2.1");
