+import java.io.Serial;
+import java.security.SecureRandomSpi;
+
+import com.oracle.jipher.internal.openssl.Rand;
+
+/**
+ * Implementation of {@link SecureRandomSpi} that uses OpenSSL's rand_bytes method to generate seed and random bytes.
+ */
+public final class Drbg extends SecureRandomSpi {
+    @Serial
+    private static final long serialVersionUID = 5952625728129925027L;
+
+    private final transient Rand rand;
+    public Drbg() {
+        this.rand = new Rand();
+    }
+
+    @Override
+    protected void engineSetSeed(byte[] seed) {
+        // Do nothing
+    }
+
+    @Override
+    protected byte[] engineGenerateSeed(int numBytes) {
+        if (numBytes < 0) {
+            throw new IllegalArgumentException("numBytes cannot be negative");
+        }
+        byte[] bytes = new byte[numBytes];
+        rand.nextBytes(bytes);
+        return bytes;
+    }
+
+    @Override
+    protected void engineNextBytes(byte[] bytes) {
+        if (bytes == null) {
+            throw new NullPointerException("bytes cannot be null");
+        }
+        this.rand.nextBytes(bytes);
+    }
+
+    /*
+     * Return a new instance of Drbg on deserialization.
+     */
+    @Serial
+    private Object readResolve() {
+        return new Drbg();
+    }
+}

