+        boolean paramsEquals(DHParameterSpec spec1, DHParameterSpec spec2) {
+            if (!spec1.getP().equals(spec2.getP())) {
+                return false;
+            }
+            return spec1.getG().equals(spec2.getG());
+        }
+    }
