+                        // invalid pair, skip to next pair
+                        if (DEBUG != null) {
+                            DEBUG.println("Ignoring invalid pair in " + p);
+                        }
+                        continue;
+                    }
+                    String algoName = algoAndValue[0].trim().toUpperCase();
