+                    try {
+                        value = Integer.parseInt(algoAndValue[1].trim());
+                    } catch (NumberFormatException nfe) {
+                        // invalid value, skip to next pair
+                        if (DEBUG != null) {
+                            DEBUG.println("Ignoring invalid value in " + p);
+                        }
+                        continue;
