+        sb.append(", MGF=MGF1(").append(((MGF1ParameterSpec) this.oaepSpec.getMGFParameters()).getDigestAlgorithm());
+        byte[] value = ((PSource.PSpecified) this.oaepSpec.getPSource()).getValue();
