+        Asn1BerValue hashAlgorithm = hashAlgToBer(this.pssSpec.getDigestAlgorithm());
+        Asn1BerValue maskGenAlgorithm = mgfToBer((MGF1ParameterSpec) this.pssSpec.getMGFParameters());
