+                .extractOnly(), SUCCESS});
+        p.add(new Object[]{policy, "short ikm extract only", HKDFParameterSpec.ofExtract()
+                .addIKM(new byte[MIN_SECURITY_STRENGTH / 8 - 1]).addSalt(new byte[0])
