+                .addIKM(new byte[MIN_SECURITY_STRENGTH / 8]).addSalt(new byte[0])
+                .thenExpand(new byte[0], 32), SUCCESS});
+        p.add(new Object[]{policy, "short ikm extract then expand parameters", HKDFParameterSpec.ofExtract()
