+        // (Re)encrypt the plaintext and add the tag
+        offset = cipherCtx.update(plaintext, 0, plaintext.length, output, 0);
+        offset += cipherCtx.doFinal(output, offset);
+        if (tagLen > 0) {
+            int tagLenInBytes = tagLen / 8;
