+        mac = libCtx.fetchMac(EVP_MAC.MAC_NAME_HMAC, null, testArena);
+        macCtx = openSsl.newEvpMacCtx(mac, testArena);
+        OSSL_PARAM params = OSSL_PARAM.of(OSSL_PARAM.ALG_PARAM_DIGEST, mdAlg);
+        macCtx.init(key, params);
+    }
+
