+            return output;
+        } else {
+            return Arrays.copyOfRange(output, 0, outLen);
+        }
+    }
+
+    private boolean doVerify(byte[] input) throws Exception {
+        return verifyCtx.verify(this.data, 0, this.data.length, input, 0, input.length);
+    }
