+
+public class VersionTest {
+
+    @Test
+    public void validVersionString() {
+        Version version = new Version("1.2.3");
+        int[] parts = version.getParts();
+
+        Assert.assertEquals(3, parts.length);
+        Assert.assertEquals(1, parts[0]);
+        Assert.assertEquals(2, parts[1]);
+        Assert.assertEquals(3, parts[2]);
+    }
+
+    @Test
+    public void versionOf() {
+        Version version = Version.of("1.2.3");
+        int[] parts = version.getParts();
+
+        Assert.assertEquals(3, parts.length);
+        Assert.assertEquals(1, parts[0]);
+        Assert.assertEquals(2, parts[1]);
+        Assert.assertEquals(3, parts[2]);
+    }
+
+    @Test
+    public void compareTo() {
+        Version version = new Version("1.2.3");
+
+        Assert.assertEquals(1, version.compareTo(null));
+
+        Assert.assertEquals(1, version.compareTo(Version.of("1")));
+        Assert.assertEquals(1, version.compareTo(Version.of("1.2")));
+        Assert.assertEquals(1, version.compareTo(Version.of("1.2.2")));
+        Assert.assertEquals(1, version.compareTo(Version.of("1.2.2.999")));
+        Assert.assertEquals(1, version.compareTo(Version.of("1.2.2.999.999")));
+
+        Assert.assertEquals(0, version.compareTo(Version.of("1.2.3")));
+        Assert.assertEquals(0, version.compareTo(Version.of("1.2.3.0")));
+        Assert.assertEquals(0, version.compareTo(Version.of("1.2.3.0.0")));
+
+        Assert.assertEquals(-1, version.compareTo(Version.of("1.2.3.0.0.1")));
+        Assert.assertEquals(-1, version.compareTo(Version.of("1.2.3.0.1")));
+        Assert.assertEquals(-1, version.compareTo(Version.of("1.2.3.1")));
+        Assert.assertEquals(-1, version.compareTo(Version.of("1.2.4")));
+        Assert.assertEquals(-1, version.compareTo(Version.of("1.3")));
+        Assert.assertEquals(-1, version.compareTo(Version.of("2")));
+    }
